css:
.print-format-gutter,
.print-format,
.page {
  padding: 0 !important;
  margin: 0 !important;
}

.letter-head,
.letter-head-name,
#letter-head,
.print-heading,
.print-heading-template {
  display: none !important;
}

@page {
  size: 100mm 80mm;
  margin: 0;
}

body {
  background: #fff;
  color: #000;
  font-family: Arial, Helvetica, sans-serif;
  margin: 0 !important;
  padding: 0 !important;
}

.label {
  width: 100mm;
  height: 80mm;
  max-height: 80mm;
  border: 0.4pt solid #000;
  display: -webkit-flex;
  display: flex;
  -webkit-flex-direction: column;
  flex-direction: column;
  overflow: hidden;
}

/* ── Barcode row ── */
.barcode-row {
  text-align: center;
  padding: 1mm 2mm 0.3mm;
  border-bottom: 0.4pt solid #000;
  -webkit-flex-shrink: 0;
  flex-shrink: 0;
}
.barcode-row svg {
  display: block;
  margin: 0 auto;
}
.tracking-no {
  font-size: 8pt;
  font-weight: bold;
  letter-spacing: 1.5px;
  margin-top: 0.5mm;
}

/* ── Address columns ── */
.columns {
  display: -webkit-flex;
  display: flex;
  -webkit-flex: 1;
  flex: 1;
  width: 100mm;
  max-width: 100mm;
  overflow: hidden;
  border-bottom: 0.4pt solid #000;
}
.col {
  -webkit-flex: 0 0 50%;
  flex: 0 0 50%;
  width: 50%;
  max-width: 50%;
  min-width: 0;
  padding: 1.5mm 2mm;
  overflow: hidden;
  box-sizing: border-box;
}
.col-sender {
  border-right: 0.4pt solid #000;
}
.col-title {
  font-size: 5.5pt;
  font-weight: bold;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  background: #000;
  color: #fff;
  padding: 0.4mm 1mm;
  margin-bottom: 1mm;
  display: block;
}
.col-name {
  font-size: 6.5pt;
  font-weight: bold;
  line-height: 1.2;
  margin-bottom: 0.5mm;
  white-space: normal;
  word-break: break-word;
  overflow-wrap: anywhere;
  display: block;
}
.col-addr {
  font-size: 6pt;
  line-height: 1.25;
  white-space: normal;
  word-break: break-word;
  overflow-wrap: anywhere;
  margin-bottom: 0.5mm;
  display: block;
}
.col-city {
  font-size: 6pt;
  font-weight: bold;
  margin-bottom: 0.5mm;
  white-space: normal;
  word-break: break-word;
  overflow-wrap: anywhere;
  display: block;
}
.col-phone {
  font-size: 6pt;
  display: block;
}

/* ── Footer ── */
.footer {
  padding: 1mm 2mm;
  font-size: 6pt;
  color: #444;
  display: -webkit-flex;
  display: flex;
  -webkit-justify-content: space-between;
  justify-content: space-between;
  -webkit-flex-shrink: 0;
  flex-shrink: 0;
}

html:
{# ─── Data Layer ─── #}

{# Sender – Company (same approach, direct from doc) #}
{% set company_name = doc.company %}
{% set sender_name = company_name %}
{% set sender_line1 = "" %}
{% set sender_district = "" %}
{% set sender_city = "" %}
{% set sender_phone = "" %}

{% if company_name %}
  {% set co_links = frappe.get_all("Dynamic Link",
      filters={"link_doctype": "Company", "link_name": company_name, "parenttype": "Address"},
      fields=["parent"], limit=1) %}
  {% if co_links %}
    {% set ca = frappe.get_doc("Address", co_links[0].parent) %}
    {% set sender_line1    = ca.address_line1 or "" %}
    {% set sender_district = ca.county or ca.state or "" %}
    {% set sender_city     = ca.city or "" %}
    {% set sender_phone    = ca.phone or "" %}
  {% endif %}
{% endif %}

{# Receiver – Customer (directly from Delivery Note, no Sales Order lookup needed) #}
{% set receiver_name     = doc.customer_name %}
{% set receiver_line1    = "" %}
{% set receiver_district = "" %}
{% set receiver_city     = "" %}
{% set receiver_phone    = "" %}

{% if doc.shipping_address_name %}
  {% set ra = frappe.get_doc("Address", doc.shipping_address_name) %}
  {% set receiver_line1    = ra.address_line1 or "" %}
  {% set receiver_district = ra.county or ra.state or "" %}
  {% set receiver_city     = ra.city or "" %}
  {% set receiver_phone    = ra.phone or "" %}
{% endif %}

{# ─── Markup ─── #}
<div class="label">

  <div class="barcode-row">
    <svg id="barcode"></svg>
    <div class="tracking-no">{{ doc.name }}</div>
  </div>

  <div class="columns">

    <div class="col col-sender">
      <span class="col-title">GÖNDERİCİ</span>
      <span class="col-name">{{ sender_name }}</span>
      {% if sender_line1 %}<span class="col-addr">{{ sender_line1 }}</span>{% endif %}
      <span class="col-city">{% if sender_district %}{{ sender_district }} / {% endif %}{{ sender_city }}</span>
      <span class="col-phone">Tel: {{ sender_phone }}</span>
    </div>

    <div class="col col-receiver">
      <span class="col-title">ALICI</span>
      <span class="col-name">{{ receiver_name }}</span>
      {% if receiver_line1 %}<span class="col-addr">{{ receiver_line1 }}</span>{% endif %}
      <span class="col-city">{% if receiver_district %}{{ receiver_district }} / {% endif %}{{ receiver_city }}</span>
      <span class="col-phone">Tel: {{ receiver_phone }}</span>
    </div>

  </div>

  <div class="footer">
    <span>{{ frappe.format(doc.creation, {"fieldtype": "Date"}) }}</span>
    <span>{{ frappe.form_dict.label_no or 1 }} / {{ frappe.form_dict.label_count or 1 }}</span>
  </div>

</div>

<script src="https://cdn.jsdelivr.net/npm/jsbarcode@3.11.5/dist/JsBarcode.all.min.js"></script>
<script>
  JsBarcode("#barcode", "{{ doc.name }}", {
    format: "CODE128",
    width: 2,
    height: 50,
    displayValue: false,
    margin: 0
  });
</script>
